206	                .get(b)
207	                .ok_or_else(|| EvalError::UndefinedVariable(b.clone()))?;
208	            let xw = x.matmul(w_arr)?;
209	            // Broadcast b ([1, out]) up to [n, out] via ones([n, 1]) @ b.
210	            let n = xw.shape().dims()[0];
211	            let ones = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
212	            let b_broadcast = ones.matmul(b_arr)?;
213	            Ok(xw.apply_binop(&b_broadcast, |a, c| a + c)?)
214	        }
215	        ModelSpec::Chain(children) => {
216	            let mut cur = x.clone();
