1	//! Tape-side lowering of the Saga 11 model DSL.
2	//!
3	//! This is the autograd twin of `model_dispatch::apply_model`: given
4	//! a `ModelSpec` and an input `Tensor` handle, it walks the model
5	//! tree and emits the same primitive ops onto the autograd tape so
6	//! that `grad(loss_with_apply, ...)` -- and therefore every optimizer
7	//! built on top of it -- can route gradients back to each layer's
8	//! trainable parameter leaves.
9	//!
10	//! Coverage today:
11	//!
12	//! - `linear`, `chain`, activation layers, `residual`, `rms_norm`,
13	//!   and single-head `attention` are fully lowered.
14	//! - Multi-head attention (`heads > 1`) is not yet supported; the
15	//!   per-head slicing it needs is not expressible with the current
16	//!   `Tensor` op surface. Use `heads = 1` or inline the per-head
17	//!   forward pass in the loss expression for now.
18	
19	use std::collections::HashMap;
20	use std::rc::Rc;
21	
22	use mlpl_array::{DenseArray, Shape};
23	use mlpl_autograd::{Tape, Tensor};
24	
25	use crate::error::EvalError;
26	use crate::model::{ActKind, ModelSpec};
27	
28	/// Tape-side analogue of `model_dispatch::apply_model`. Walks the
29	/// model and emits the matching primitive ops on the autograd tape.
30	pub(crate) fn apply_model_tape(
31	    model: &ModelSpec,
32	    x: Tensor,
33	    tape: &Rc<Tape>,
34	    params: &HashMap<String, Tensor>,
35	) -> Result<Tensor, EvalError> {
36	    match model {
37	        ModelSpec::Linear { w, b } => linear_tape(&x, w, b, tape, params),
38	        ModelSpec::Chain(children) => {
39	            let mut cur = x;
40	            for child in children {
41	                cur = apply_model_tape(child, cur, tape, params)?;
42	            }
43	            Ok(cur)
44	        }
45	        ModelSpec::Activation(kind) => Ok(match kind {
46	            ActKind::Tanh => x.tanh(),
47	            ActKind::Relu => x.relu(),
48	            ActKind::Softmax => x.softmax(),
49	        }),
50	        ModelSpec::Residual(inner) => {
51	            let inner_out = apply_model_tape(inner, x.clone(), tape, params)?;
52	            Ok(x.add(&inner_out))
53	        }
54	        ModelSpec::RmsNorm { .. } => rms_norm_tape(&x, tape),
55	        ModelSpec::Attention {
56	            wq,
57	            wk,
58	            wv,
59	            wo,
60	            d_model,
61	            heads,
62	        } => {
63	            if *heads != 1 {
64	                return Err(EvalError::Unsupported(format!(
65	                    "grad: apply() through multi-head attention (heads={heads}) is not \
66	                     yet supported on the autograd tape; use heads=1 or inline the \
67	                     per-head forward pass in the loss expression"
68	                )));
69	            }
70	            let inputs = AttentionInputs {
71	                wq,
72	                wk,
73	                wv,
74	                wo,
75	                d_model: *d_model,
76	            };
77	            attention_single_head_tape(&x, &inputs, tape, params)
78	        }
79	    }
80	}
81	
82	fn linear_tape(
83	    x: &Tensor,
84	    w: &str,
85	    b: &str,
86	    tape: &Rc<Tape>,
87	    params: &HashMap<String, Tensor>,
88	) -> Result<Tensor, EvalError> {
89	    let w_t = params
90	        .get(w)
91	        .cloned()
92	        .ok_or_else(|| EvalError::UndefinedVariable(w.into()))?;
93	    let b_t = params
94	        .get(b)
95	        .cloned()
96	        .ok_or_else(|| EvalError::UndefinedVariable(b.into()))?;
97	    let xw = x.matmul(&w_t);
98	    // b is [1, out]; lift to [n, out] via ones([n, 1]) @ b so the
99	    // tape graph matches the hand-rolled broadcast form exactly.
100	    let n = xw.value().shape().dims()[0];
101	    let ones_arr = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
102	    let ones_t = Tensor::leaf(Rc::clone(tape), ones_arr, false);
103	    Ok(xw.add(&ones_t.matmul(&b_t)))
104	}
105	
106	/// Per-row RMS normalization on the tape:
107	/// `y[i, :] = x[i, :] / sqrt(mean(x[i, :]^2) + eps)`.
108	/// `sqrt(v)` is encoded as `exp(-0.5 * log(v))` because the tape
109	/// does not yet expose a direct sqrt op. Per-row mean is encoded as
110	/// `matmul(x, ones([cols, 1])) / cols`, and the broadcast back to
111	/// `[rows, cols]` as `rsqrt @ ones([1, cols])`.
112	fn rms_norm_tape(x: &Tensor, tape: &Rc<Tape>) -> Result<Tensor, EvalError> {
113	    let dims = x.value().shape().dims().to_vec();
114	    if dims.len() != 2 {
115	        return Err(EvalError::Unsupported(
116	            "rms_norm: input must be a rank-2 [rows, cols] matrix".into(),
117	        ));
118	    }
119	    let cols = dims[1];
120	    let eps = 1e-8_f64;
121	    let leaf = |v: DenseArray| Tensor::leaf(Rc::clone(tape), v, false);
122	    let ones_col = leaf(DenseArray::new(Shape::new(vec![cols, 1]), vec![1.0; cols])?);
123	    let ones_row = leaf(DenseArray::new(Shape::new(vec![1, cols]), vec![1.0; cols])?);
124	    let inv_cols = leaf(DenseArray::from_scalar(1.0 / cols as f64));
125	    let eps_t = leaf(DenseArray::from_scalar(eps));
126	    let half_neg = leaf(DenseArray::from_scalar(-0.5));
127	    let row_mean_eps = x.mul(x).matmul(&ones_col).mul(&inv_cols).add(&eps_t);
128	    let rsqrt = row_mean_eps.log().mul(&half_neg).exp();
129	    Ok(x.mul(&rsqrt.matmul(&ones_row)))
130	}
131	
132	/// Bundle of attention parameter names + model dimension so the
133	/// tape helper stays inside the 7-arg clippy budget without needing
134	/// `#[allow(clippy::too_many_arguments)]`.
135	struct AttentionInputs<'a> {
136	    wq: &'a str,
137	    wk: &'a str,
138	    wv: &'a str,
139	    wo: &'a str,
140	    d_model: usize,
141	}
142	
143	/// Single-head scaled-dot-product attention on the tape. Multi-head
144	/// requires slicing that the autograd substrate does not yet expose.
145	fn attention_single_head_tape(
146	    x: &Tensor,
147	    inputs: &AttentionInputs<'_>,
148	    tape: &Rc<Tape>,
149	    params: &HashMap<String, Tensor>,
150	) -> Result<Tensor, EvalError> {
151	    let dims = x.value().shape().dims().to_vec();
152	    if dims.len() != 2 || dims[1] != inputs.d_model {
