fn apply_embed_gathers_rows_by_token_id() {
    // Build an embedding then overwrite the table with a known matrix.
    let mut env = Environment::new();
    eval_program(
        &parse(&lex("E = embed(5, 3, 1)").unwrap()).unwrap(),
