        vec![5, 3],
        vec![
            0.0, 0.1, 0.2, // row 0
            1.0, 1.1, 1.2, // row 1
            2.0, 2.1, 2.2, // row 2
            3.0, 3.1, 3.2, // row 3
            4.0, 4.1, 4.2, // row 4
        ],
    );
    env.set(names[0].clone(), table);
    env.set("toks".into(), arr(vec![3], vec![0.0, 2.0, 4.0]));
    let out = run("apply(E, toks)", &mut env);
    assert_eq!(out.shape().dims(), &[3, 3]);
    assert_eq!(
        out.data(),
