#[test]
fn adam_step_reduces_embedding_loss() {
    // sum(apply(E, toks) * apply(E, toks)) is a quadratic in the rows
    // of the table touched by `toks`. One adam step must reduce it.
    let mut env = Environment::new();
    eval_program(
        &parse(&lex("E = embed(4, 2, 11)").unwrap()).unwrap(),
        &mut env,
    )
    .unwrap();
    let names = model_params(&env, "E").unwrap();
    env.set(
        names[0].clone(),
        arr(vec![4, 2], vec![1.0, -1.0, 0.5, 0.5, -0.5, 0.25, 0.0, 0.0]),
    );
    env.set("toks".into(), arr(vec![3], vec![0.0, 1.0, 2.0]));

    // Capture the initial loss.
    let loss0 = run("sum(apply(E, toks) * apply(E, toks))", &mut env);
    let l0 = loss0.data()[0];

    // Run 50 adam steps; the Frobenius norm of the touched rows must shrink.
    eval_program(
        &parse(&lex(
            "train 50 { adam(sum(apply(E, toks) * apply(E, toks)), E, 0.05, 0.9, 0.999, 0.00000001) }",
        ).unwrap()).unwrap(),
        &mut env,
    ).unwrap();

    let loss1 = run("sum(apply(E, toks) * apply(E, toks))", &mut env);
    let l1 = loss1.data()[0];
    assert!(l1 < l0, "expected loss to decrease, got {l0} -> {l1}");
    assert!(l1 < 0.5 * l0, "expected loss to halve, got {l0} -> {l1}");
