107	#[test]
108	fn grad_through_apply_embed_matches_one_hot_form() {
109	    // grad(loss, table) for an embedding lookup must equal grad of the
110	    // hand-written `O @ table` form, where O is the [N, V] one-hot of
111	    // the token ids. This is the gradcheck for the embedding layer.
112	    let mut env = Environment::new();
113	    let setup = "\
114	        E = embed(4, 2, 5)\n\
115	        toks = [0.0, 2.0, 1.0, 2.0]\n\
116	        ONE = [[1.0, 0.0, 0.0, 0.0], \
117	               [0.0, 0.0, 1.0, 0.0], \
118	               [0.0, 1.0, 0.0, 0.0], \
119	               [0.0, 0.0, 1.0, 0.0]]\n";
120	    eval_program(&parse(&lex(setup).unwrap()).unwrap(), &mut env).unwrap();
121	    let names = model_params(&env, "E").unwrap();
122	    let table = names[0].clone();
123	
124	    let g_apply = run(&format!("grad(sum(apply(E, toks)), {table})"), &mut env);
125	    let g_hand = run(
126	        &format!("grad(sum(matmul(ONE, {table})), {table})"),
127	        &mut env,
128	    );
129	    assert_eq!(g_apply.shape(), g_hand.shape());
130	    for (a, b) in g_apply.data().iter().zip(g_hand.data().iter()) {
131	        assert!((a - b).abs() < 1e-10, "grad mismatch: {a} vs {b}");
132	    }
133	    // Repeated token id 2 must accumulate: row 2 of the gradient should
134	    // be twice the contribution of a single row.
135	    let g = g_apply.data();
136	    assert!((g[2 * 2] - 2.0).abs() < 1e-10, "row 2 col 0 expected 2.0");
137	    assert!(
138	        (g[2 * 2 + 1] - 2.0).abs() < 1e-10,
139	        "row 2 col 1 expected 2.0"
140	    );
141	}
