143	#[test]
144	fn adam_step_reduces_embedding_loss() {
145	    // sum(apply(E, toks) * apply(E, toks)) is a quadratic in the rows
146	    // of the table touched by `toks` (rows 0, 1, 2). 50 Adam steps must
147	    // shrink those rows toward zero. Row 3 is untouched and so its
148	    // norm should be unchanged. We can't read sum() outside grad/opt,
149	    // so we verify by inspecting the table directly after training.
150	    let mut env = Environment::new();
151	    eval_program(
152	        &parse(&lex("E = embed(4, 2, 11)").unwrap()).unwrap(),
153	        &mut env,
154	    )
155	    .unwrap();
156	    let names = model_params(&env, "E").unwrap();
157	    let table_name = names[0].clone();
158	    env.set(
159	        table_name.clone(),
160	        arr(vec![4, 2], vec![1.0, -1.0, 0.5, 0.5, -0.5, 0.25, 9.0, -9.0]),
161	    );
162	    env.set("toks".into(), arr(vec![3], vec![0.0, 1.0, 2.0]));
163	
164	    let row_norm = |t: &DenseArray, r: usize| -> f64 {
165	        let d = t.data();
166	        (d[r * 2] * d[r * 2] + d[r * 2 + 1] * d[r * 2 + 1]).sqrt()
167	    };
168	    let table0 = env.get(&table_name).unwrap().clone();
169	    let n0_0 = row_norm(&table0, 0);
170	    let n0_1 = row_norm(&table0, 1);
171	    let n0_2 = row_norm(&table0, 2);
172	    let n0_3 = row_norm(&table0, 3);
173	
174	    eval_program(
175	        &parse(&lex(
176	            "train 50 { adam(sum(apply(E, toks) * apply(E, toks)), E, 0.05, 0.9, 0.999, 0.00000001) }",
177	        ).unwrap()).unwrap(),
178	        &mut env,
179	    ).unwrap();
180	
181	    let table1 = env.get(&table_name).unwrap().clone();
182	    let n1_0 = row_norm(&table1, 0);
183	    let n1_1 = row_norm(&table1, 1);
184	    let n1_2 = row_norm(&table1, 2);
185	    let n1_3 = row_norm(&table1, 3);
186	
187	    assert!(n1_0 < n0_0, "row 0 expected to shrink, {n0_0} -> {n1_0}");
188	    assert!(n1_1 < n0_1, "row 1 expected to shrink, {n0_1} -> {n1_1}");
189	    assert!(n1_2 < n0_2, "row 2 expected to shrink, {n0_2} -> {n1_2}");
190	    assert!(
191	        (n1_3 - n0_3).abs() < 1e-12,
192	        "row 3 (untouched by toks) must be unchanged, {n0_3} -> {n1_3}"
193	    );
194	}
